const data = $input.first().json;
const payload = data.payload || {};
const from = payload.from || '';
const remoteJid = payload._data?.key?.remoteJid || '';

// BLOQUEAR: mensagens proprias
if (payload.fromMe) return [];

// BLOQUEAR: grupos
if (from.includes('@g.us') || remoteJid.includes('@g.us')) return [];

// BLOQUEAR: status/broadcast/newsletter/lid sem alt
if (from.includes('@broadcast') || remoteJid.includes('@broadcast')) return [];
if (from.includes('@newsletter') || remoteJid.includes('@newsletter')) return [];
if (from === 'status@broadcast' || remoteJid === 'status@broadcast') return [];

// BLOQUEAR: sem texto
const text = (payload.body || payload.text || '').trim();
if (!text) return [];

// RATE LIMIT: ignorar se ultima msg do mesmo remetente foi ha menos de 3 segundos
const now = Date.now();
const msgTimestamp = (payload.timestamp || 0) * 1000;
const globalState = $getWorkflowStaticData('global');
const lastMsgKey = 'last_' + from;
const lastTime = globalState[lastMsgKey] || 0;
if (now - lastTime < 3000) return [];
globalState[lastMsgKey] = now;

// Limpar entradas antigas (mais de 1 hora) para nao acumular memoria
for (const key of Object.keys(globalState)) {
  if (key.startsWith('last_') && now - globalState[key] > 3600000) {
    delete globalState[key];
  }
}

// Pegar chatId real
const chatId = payload._data?.key?.remoteJidAlt || from;
const phone = chatId.replace(/@s\.whatsapp\.net$/, '').replace(/@c\.us$/, '').replace(/@lid$/, '').replace(/\D/g, '');
const whatsapp_id = phone + '@c.us';

// Nome do usuario
const pushName = payload._data?.pushName || data.me?.pushName || '';
const nome = pushName.split(' ')[0] || 'chefe';

return [{ json: { phone, whatsapp_id, chatId, text, nome } }];

const filtro = $('Filtrar Mensagem').first().json;
const dbResult = $input.first().json;

const temPendencia = dbResult.tarefa_pendente_id ? true : false;

return [{ json: { ...filtro, temPendencia, tarefa_pendente_id: dbResult.tarefa_pendente_id || null, tarefa_pendente_titulo: dbResult.tarefa_pendente_titulo || null } }];

const text = $input.first().json.text;
const hoje = new Date().toISOString().split('T')[0];

const prompt = 'O usuario informou uma data para uma tarefa pendente. Extraia a data do texto e retorne APENAS um objeto JSON puro com dois campos: data (formato YYYY-MM-DD) e resposta (confirmacao na voz do Tarefildo Silva das Pendencias que eh um funcionario raiz sarcastico e engracado). Hoje eh ' + hoje + '. Se disser amanha calcule a data. Se disser sexta calcule a proxima sexta. Se nao conseguir extrair a data retorne data vazio e na resposta peca a data novamente no estilo do Tarefildo.';

return [{ json: { prompt, text } }];

const input = $input.first().json;
const state = $('Preparar Estado').first().json;

let data = '';
let resposta = '';

try {
  let raw = input.choices[0].message.content.trim();
  raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) raw = match[0];
  const parsed = JSON.parse(raw);
  data = parsed.data || '';
  resposta = parsed.resposta || '';
} catch(e) {
  data = '';
  resposta = 'Nao entendi a data. Pode falar tipo "dia 25" ou "proxima sexta"? 📅';
}

return [{ json: { ...state, data_extraida: data, resposta_data: resposta } }];

