const db = $input.first().json;
const state = $('Preparar Estado').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const d = db.data_vencimento || '';
const titulo = db.titulo || state.tarefa_pendente_titulo;
let dataFormatada = '';
if (d) {
  const parts = d.split('T')[0].split('-');
  dataFormatada = `${parts[2]}/${parts[1]}/${parts[0]}`;
}
const msg = `Pronto ${nome}, '${titulo}' agendado pro dia ${dataFormatada}. Isso aqui ja era pra ontem mas pelo menos agora ta no radar 👀 Tamo junto nas pendencias.`;
return [{ json: { chatId: state.chatId, mensagem: msg } }];

const state = $('Preparar Estado').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const msg = `${nome}, nao consegui pegar essa data nao. Me fala tipo 'dia 25' ou 'proxima sexta'. Se nao anotar, esquece... e eu nao quero te ver esquecendo 😬`;
return [{ json: { chatId: state.chatId, mensagem: msg } }];

const input = $input.first().json;
const state = $('Preparar Estado').first().json;

if (input.error || !input.choices) {
  return [{ json: { intent: 'conversa', dados: {}, resposta: 'Opa, tive um probleminha. Tenta de novo? 😅', phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];
}

let raw = input.choices[0].message.content.trim();
raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (jsonMatch) raw = jsonMatch[0];

let parsed;
try {
  parsed = JSON.parse(raw);
  if ((parsed.intent === 'outro' || parsed.intent === 'conversa') && parsed.resposta && parsed.resposta.includes('"intent"')) {
    const inner = parsed.resposta.match(/\{[\s\S]*\}/);
    if (inner) { try { const p = JSON.parse(inner[0]); if (p.intent) parsed = p; } catch(e) {} }
  }
} catch(e) {
  parsed = { intent: 'conversa', dados: {}, resposta: raw.length < 300 ? raw : 'Nao entendi, pode repetir? 🙏' };
}

if (parsed.intent === 'outro') parsed.intent = 'conversa';
if (!parsed.resposta) parsed.resposta = 'Tudo certo! 😊';
if (!parsed.dados) parsed.dados = {};

return [{ json: { ...parsed, phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];

const data = $input.first().json;
const temData = data.dados?.data && data.dados.data.trim() !== '';
const status = temData ? 'PENDENTE' : 'AGUARDANDO_DATA';
const hora = data.dados?.hora || '';
return [{ json: { ...data, status_tarefa: status, tem_data: temData, hora } }];

const db = $input.first().json;
const state = $('Parsear NLP').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
let msg;

if (db.status === 'AGUARDANDO_DATA') {
  msg = `Anotado aqui, ${nome}: "${db.titulo}". Agora nao some nao hein 👀 Me fala a data que eu travo no calendario.`;
} else {
  let dataFormatada = '';
  if (db.data_vencimento) {
    const parts = db.data_vencimento.split('T')[0].split('-');
    dataFormatada = `${parts[2]}/${parts[1]}/${parts[0]}`;
  }
  const hora = db.hora_vencimento ? db.hora_vencimento.substring(0, 5) : '';
  if (dataFormatada && hora) {
    msg = `${nome}, "${db.titulo}" travado pro dia ${dataFormatada} as ${hora}. Se nao anotar, esquece. Mas o Tarefildo anotou por voce 😄`;
  } else if (dataFormatada) {
    msg = `${nome}, "${db.titulo}" marcado pro dia ${dataFormatada}. Confia no processo... e no Tarefildo. Eu te lembro.`;
  } else {
    msg = `"${db.titulo}" anotado, ${nome}. Bora resolver isso ai.`;
  }
}

return [{ json: { chatId: state.chatId, mensagem: msg } }];

