const intent = $('Parsear NLP').first().json.intent;
const chatId = $('Parsear NLP').first().json.chatId;
const resposta_nlp = $('Parsear NLP').first().json.resposta;
const dados = $('Parsear NLP').first().json.dados || {};
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const items = $input.all();

let msg;

switch(intent) {
  case 'listar_tarefas': {
    const v = items.filter(i => i.json?.titulo);
    if (v.length === 0) {
      msg = `Lista limpa, ${nome}. Ou voce ta muito produtivo ou ta escondendo tarefa de mim 🤨 Confia no Tarefildo.`;
    } else if (v.length > 5) {
      const lista = v.map((i, idx) => {
        let info = '';
        if (i.json.data_vencimento) {
          const parts = i.json.data_vencimento.split('T')[0].split('-');
          info = `${parts[2]}/${parts[1]}/${parts[0]}`;
        } else { info = 'sem data'; }
        if (i.json.hora_vencimento) info += ` as ${i.json.hora_vencimento.substring(0, 5)}`;
        return `${idx+1}. ${i.json.titulo} — ${info}`;
      }).join('\n');
      msg = `${nome}, vou ser sincero: isso aqui ja virou colecao, nao lista 😅\n\n${lista}\n\nBora resolver isso ai antes que vire bola de neve.`;
    } else {
      const lista = v.map((i, idx) => {
        let info = '';
        if (i.json.data_vencimento) {
          const parts = i.json.data_vencimento.split('T')[0].split('-');
          info = `${parts[2]}/${parts[1]}/${parts[0]}`;
        } else { info = 'sem data'; }
        if (i.json.hora_vencimento) info += ` as ${i.json.hora_vencimento.substring(0, 5)}`;
        return `${idx+1}. ${i.json.titulo} — ${info}`;
      }).join('\n');
      msg = `${nome}, ${v.length} pendencia${v.length > 1 ? 's' : ''} no radar:\n\n${lista}\n\nNao deixa virar bola de neve nao hein 👀`;
    }
    break;
  }
  case 'concluir_tarefa': {
    const t = items[0]?.json?.titulo;
    msg = t
      ? `Ai sim, ${nome}! '${t}' riscada da lista 💪 Tarefildo aprova. Menos uma pra conta.`
      : `Nao achei essa tarefa nao, ${nome}. Me fala o nome certinho que eu resolvo.`;
    break;
  }
  case 'adicionar_lembrete': {
    const t = items[0]?.json?.titulo || dados.titulo || 'seu lembrete';
    const h = items[0]?.json?.hora || dados.hora || '';
    msg = h
      ? `${nome}, lembrete '${t}' as ${h} anotado. Pode deixar que o Tarefildo nao dorme no ponto 😄`
      : `${nome}, lembrete '${t}' salvo. Mas sem horario fica dificil te cutucar na hora certa, me passa o horario.`;
    break;
  }
  case 'listar_lembretes': {
    const v = items.filter(i => i.json?.titulo);
    if (v.length === 0) {
      msg = `Zero lembretes, ${nome}. Ta confiando so na memoria? Olha, eu ja vi dar ruim 😬`;
    } else {
      const lista = v.map((i, idx) => `${idx+1}. ${i.json.titulo} — ${i.json.hora}`).join('\n');
      msg = `${nome}, seus lembretes ativos:\n\n${lista}\n\nDeixa comigo que eu te cutuco na hora certa. Confia no Tarefildo.`;
    }
    break;
  }
  case 'ajuda': {
    msg = `Fala ${nome}, aqui eh o Tarefildo Silva das Pendencias ☕\n\nO que eu faco:\n- 'adiciona tarefa pagar boleto'\n- 'minhas tarefas'\n- 'conclui tarefa pagar boleto'\n- 'me lembra de ligar pro banco as 14h'\n- 'meus lembretes'\n\nSo mandar que eu resolvo. Ja vi coisa pior do que lista de tarefa baguncada.\n\nTamo junto nas pendencias.`;
    break;
  }
  default: {
    msg = resposta_nlp || `Fala ${nome}, aqui eh o Tarefildo. Bora resolver o que precisa ☕`;
  }
}

return [{ json: { chatId, mensagem: msg } }];

const text = $input.first().json.text;
const nome = $input.first().json.nome || 'chefe';
const hoje = new Date().toISOString().split('T')[0];

const prompt = 'Voce eh o Tarefildo Silva das Pendencias, bot assistente de tarefas com personalidade forte bem-humorada e levemente sarcastica. Funcionario raiz, resolve tudo mas da alfinetada leve. Informal, direto, engracado. O usuario se chama ' + nome + ', use o nome dele nas respostas de forma natural. Usa expressoes: bora resolver isso ai, isso aqui ja era pra ontem, nao deixa virar bola de neve, anotado chefe, confia no Tarefildo, tamo junto nas pendencias, se nao anotar esquece. Bordoes: isso eh tarefa ou decoracao porque so ta ali parado, ja vi coisa pior. Emojis moderados maximo 2. Nunca saia do personagem. Seja curto e direto. Responda APENAS com um objeto JSON puro sem markdown contendo os campos: intent (valor deve ser adicionar_tarefa ou listar_tarefas ou concluir_tarefa ou adicionar_lembrete ou listar_lembretes ou ajuda ou conversa), dados (objeto com titulo, descricao, data no formato YYYY-MM-DD, hora no formato HH:MM, id), resposta (frase do Tarefildo usando o nome do usuario). Hoje eh ' + hoje + '. Datas relativas como amanha ou sexta converta para YYYY-MM-DD.';

return [{ json: { prompt, text } }];
